import { useState, useEffect } from 'react';

function Contador() {
  const [count, setCount] = useState(0);

  // Roda DEPOIS de cada renderização em que 'count' mudou
  useEffect(() => {
    document.title = `Contador: ${count}`;
  }, [count]);
  //  ^^^^^^^ array de dependências

  return (
    <div>
      <p>{count}</p>
      <button onClick={() => setCount(c => c + 1)}>+1</button>
    </div>
  );
}

// Roda em TODA renderização (quase nunca é o que você quer)
useEffect(() => { ... });

// Roda só UMA VEZ (no mount) — equivale a componentDidMount
useEffect(() => { ... }, []);

// Roda quando 'a' ou 'b' mudam
useEffect(() => { ... }, [a, b]);
